<div class="response-msg"></div>
<style>
    p.extend_partic {
        text-align: center;
        margin-top: 160px;
        font-size: 18px;
    }
</style>
<script>

    jQuery(document).ready(function ($) {

        // Add the dates you want to disable manually
        var disabledDates = [ 
            "2026-01-01",  
            "2026-01-26", // Republic Day 
            "2026-03-04", // Holi
            "2026-03-20", // Eid  
            "2026-08-15", // Independence Day 
            "2026-08-28", // Rakhi 
            "2026-10-02", // Gandhi Jayanti
            "2026-10-20", // Dussehra
            "2026-11-08", // Diwali
            "2026-11-09", // Guru Nanak Jayanti
            "2026-12-25"  // Christmas
        ];


        $("#sf_date").datepicker({
            minDate: 0, // Disable past days
            dateFormat: 'yy-mm-dd', // Consistent format
            dayNamesMin: [  "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" ],
            beforeShowDay: function (date) {
                var day = date.getDay();
                var formattedDate = $.datepicker.formatDate('yy-mm-dd', date);

                // Disable weekends (0 = Sunday, 6 = Saturday)
                if (day === 0) {
                    //return [false, "", "Weekends not available"];
                }

                // Disable custom dates
                if ($.inArray(formattedDate, disabledDates) !== -1) {
                    return [false, "", "Date not available"];
                }

                // All other dates are enabled
                return [true, ""];
            }
        });

        jQuery(document).on("click", "#sf_search_btn", function (e) {
            e.preventDefault();



            let sf_date = $("#sf_date").val();
            let sf_slot = $("#sf_slot").val();
            let sf_participants = $("#sf_participants").val();

            if (!sf_date) {
                $('.search_filter_bar').addClass("empty-error");
                return;
            } else {
                $('.search_filter_bar').removeClass("empty-error");
            }

            $(this).addClass("loading");
            $(".response-msg").html("");
            console.log(sf_date + " | " + sf_slot + " | " + sf_participants);

            // Start AJAX
            jQuery.post(my_ajax_obj.ajaxurl, {
                action: "search_rooms",
                sf_date: sf_date,
                sf_slot: sf_slot,
                sf_participants: sf_participants
            }, function (response) {
                $('#sf_search_btn').removeClass("loading");
                $('#all_rooms').removeClass("defaults");
                $('#all_rooms').addClass("results");

                const products = Array.isArray(response.available_products) ? response.available_products : [];

                // Convert IDs into class names
                const allowedClasses = products.map(p => "e-loop-item-" + p.ID);


                // 🔥 CASE 1: response is NOT array OR empty array
                if (allowedClasses.length === 0) {

                    // Show message from server OR fallback
                    document.querySelector(".response-msg").innerHTML =
                        response || "<p>No rooms available</p>";

                    // Hide all items
                    const allItems = document.querySelectorAll("[class*='e-loop-item-']");
                    allItems.forEach(item => item.style.display = "none");

                    return; // stop execution
                }


                // 🔥 CASE 2: valid array → normal filtering
                const items = document.querySelectorAll("[class*='e-loop-item-']");

                items.forEach(item => {
                    const shouldShow = allowedClasses.some(cls => item.classList.contains(cls));
                    item.style.display = shouldShow ? "block" : "none";
                    const btn = item.querySelector('.bookbtn a');
                    btn.href = btn.href.split('?')[0];
                    btn.href += `?date=${sf_date}&slot=${sf_slot}`;
                });

            }).fail(function () {
                console.log("Something went wrong. Please try again.");
                $('#sf_search_btn').removeClass("loading");
            });

        });

        jQuery(document).on("click", "#sf_clear_btn", function (e) {
            e.preventDefault();

            $('#all_rooms').removeClass("results");
            $('#all_rooms').addClass("defaults");
            const items = document.querySelectorAll("[class*='e-loop-item-']");

            $("#sf_date").val("");
            $("#sf_slot").val("");
            $("#sf_participants").val("");
            $("div#sf_slot_selected").html("Select Time Slot");
            $(".response-msg").html("");
            $('.search_filter_bar').removeClass("empty-error");
            items.forEach(item => {
                item.style.display = "block";
                const btn = item.querySelector('.bookbtn a');
                btn.href = btn.href.split('?')[0];
            });
        });

    });

</script>
<script>
const wrapper = document.getElementById("sf_slot_wrapper");
const slot_wrap = document.getElementById("slot_wrap");
const selected = document.getElementById("sf_slot_selected");
const list = document.getElementById("sf_slot_list");
const hiddenInput = document.getElementById("sf_slot");

// FIXED SECTION: Pass 'e' (event) and use stopPropagation()
slot_wrap.addEventListener("click", (e) => {
    e.stopPropagation(); // <--- This prevents the document listener from firing immediately
    wrapper.classList.toggle("open");
});

list.querySelectorAll("li").forEach(item => {
    item.addEventListener("click", (e) => {
        // Optional: Stop propagation here too if clicking an item shouldn't trigger document clicks
        e.stopPropagation(); 
        
        selected.textContent = item.textContent;
        hiddenInput.value = item.getAttribute("data-value");
        wrapper.classList.remove("open");
    });
});

/* Close dropdown when clicking outside */
document.addEventListener("click", (e) => {
    // We check if the click was inside slot_wrap (the main container), not just wrapper
    if (!slot_wrap.contains(e.target)) {
        wrapper.classList.remove("open");
    }
});
</script>